#include <iostream>

int main() {
    int n;
    std::cin >> n;
    int x;
    std::cin >> x;
    int max = x, min = x;
    for (int i = 1; i < n; i++) {
        std::cin >> x;
        if (x > max) max = x;
        if (x < min) min = x;
    }
    std::cout << max << " " << min << std::endl;
    return 0;
}
